INSERT INTO products (id, name, slug, description, brand_id, category_id, price, compare_at_price, attributes, rating_avg, rating_count, is_active, is_featured) VALUES
('00000000-0000-0000-0000-00000cae3528', 'Coco Noir Eau de Parfum', 'coco-noir-eau-de-parfum', 'A warm, sensual fragrance built around Grasse jasmine and Bulgarian rose, finished with a smoky vetiver base. The elegant black glass bottle refills, so you can keep the same bottle for years. 100ml spray.', '00000000-0000-0000-0000-000028f9fcc9', '00000000-0000-0000-0000-000032b398c1', 128.0, 160.0, '{}'::jsonb, 4.7, 5689, true, true),
('00000000-0000-0000-0000-000017d94b7e', 'Revitalift Anti-Aging Serum', 'revitalift-anti-aging-serum', 'A lightweight daily serum with 1.5% pure hyaluronic acid that plumps fine lines within one week of use. Fragrance-free, dermatologist-tested, and suitable for all skin types. 30ml pump bottle.', '00000000-0000-0000-0000-0000040c4587', '00000000-0000-0000-0000-000032b398c1', 24.99, 32.99, '{}'::jsonb, 4.4, 12890, true, false),
('00000000-0000-0000-0000-00002984eed5', 'Matte Velvet Lipstick Set', 'matte-velvet-lipstick-set', 'A set of 3 full-size matte lipsticks in universally flattering shades — nude, rose, and classic red. Long-wearing, transfer-resistant formula that stays comfortable for up to 8 hours.', '00000000-0000-0000-0000-0000040c4587', '00000000-0000-0000-0000-000032b398c1', 18.5, NULL, '{}'::jsonb, 4.2, 3021, true, false),
('00000000-0000-0000-0000-00003af411b3', 'Hydrating Facial Moisturizer', 'hydrating-facial-moisturizer', 'A rich 24-hour moisturizer with ceramides and glycerin that restores the skin barrier without feeling greasy. Non-comedogenic and safe for sensitive skin. 50ml jar.', '00000000-0000-0000-0000-0000040c4587', '00000000-0000-0000-0000-000032b398c1', 21.0, 26.0, '{}'::jsonb, 4.5, 8760, true, false),
('00000000-0000-0000-0000-00000cc8b55c', 'Luxury Rose Perfume Gift Set', 'luxury-rose-perfume-gift-set', 'A gift-ready set pairing a 50ml rose eau de parfum with a matching travel-size rollerball, presented in a satin-lined box. A best-seller during the holiday season.', '00000000-0000-0000-0000-000028f9fcc9', '00000000-0000-0000-0000-000032b398c1', 89.99, NULL, '{}'::jsonb, 4.6, 2140, true, true),
('00000000-0000-0000-0000-000026351c0d', 'Classic Denim Jacket', 'classic-denim-jacket', 'A mid-wash denim jacket cut for a relaxed fit, with button cuffs and chest flap pockets. A wardrobe staple that layers over almost anything, from a t-shirt to a dress.', '00000000-0000-0000-0000-000021f63c26', '00000000-0000-0000-0000-000032c7b03e', 64.99, 89.99, '{"sizes":["XS","S","M","L","XL"],"colors":["Blue","Black"]}'::jsonb, 4.3, 4410, true, true),
('00000000-0000-0000-0000-000010a1f0e7', 'Oversized Knit Sweater', 'oversized-knit-sweater', 'A soft, chunky-knit sweater with dropped shoulders and ribbed cuffs. Breathable cotton-wool blend, machine washable, and roomy enough to layer over a shirt.', '00000000-0000-0000-0000-000032477ac9', '00000000-0000-0000-0000-000032c7b03e', 39.99, NULL, '{"sizes":["S","M","L"],"colors":["Cream","Grey","Green"]}'::jsonb, 4.1, 1875, true, false),
('00000000-0000-0000-0000-00000debeb7d', 'Leather Crossbody Bag', 'leather-crossbody-bag', 'A compact crossbody in genuine leather with an adjustable strap and three interior compartments. Roomy enough for a phone, cards, and keys without the bulk.', '00000000-0000-0000-0000-000021f63c26', '00000000-0000-0000-0000-000032c7b03e', 74.5, 99.0, '{"colors":["Tan","Black"]}'::jsonb, 4.6, 3302, true, false),
('00000000-0000-0000-0000-000000264ff2', 'Classic Aviator Sunglasses', 'classic-aviator-sunglasses', 'Timeless aviator-shaped sunglasses with UV400-rated polarized lenses and a lightweight metal frame. Comes with a hard case and microfiber cleaning cloth.', '00000000-0000-0000-0000-000032477ac9', '00000000-0000-0000-0000-000032c7b03e', 22.0, NULL, '{}'::jsonb, 4.0, 986, true, false),
('00000000-0000-0000-0000-000029602266', 'Canvas Tote Bag', 'canvas-tote-bag', 'A heavy-duty canvas tote with reinforced stitching and a flat base that stands on its own. Big enough for a laptop, a change of clothes, or a grocery run.', '00000000-0000-0000-0000-000021f63c26', '00000000-0000-0000-0000-000032c7b03e', 29.99, NULL, '{}'::jsonb, 4.4, 2205, true, true),
('00000000-0000-0000-0000-00001771952b', 'Teddy Bear Fleece Romper', 'teddy-bear-fleece-romper', 'An ultra-soft fleece romper with bear ears on the hood and a full-length zip for quick changes. Machine washable and safe for sensitive baby skin.', '00000000-0000-0000-0000-000036e22902', '00000000-0000-0000-0000-00000d44de42', 27.99, 34.99, '{"sizes":["0-3M","3-6M","6-12M"]}'::jsonb, 4.8, 6890, true, true),
('00000000-0000-0000-0000-00002dbc41be', 'Boys'' Cardigan & Shorts Set', 'boys-cardigan-and-shorts-set', 'A smart two-piece set — a button-front cardigan over a collared shirt, paired with matching shorts. Perfect for parties, photos, or any occasion that calls for a little extra polish.', '00000000-0000-0000-0000-00002ff47c08', '00000000-0000-0000-0000-00000d44de42', 32.5, NULL, '{"sizes":["2T","3T","4T","5T"]}'::jsonb, 4.5, 1523, true, false),
('00000000-0000-0000-0000-000021ea2a1a', 'Girls'' Floral Summer Dress', 'girls-floral-summer-dress', 'A breathable cotton dress with an all-over floral print and a twirl-friendly skirt. Machine washable and colorfast after repeated washes.', '00000000-0000-0000-0000-00002ff47c08', '00000000-0000-0000-0000-00000d44de42', 26.0, 32.0, '{"sizes":["2T","3T","4T","5T","6T"]}'::jsonb, 4.6, 2870, true, false),
('00000000-0000-0000-0000-0000103686b4', 'Kids Denim Overalls', 'kids-denim-overalls', 'Durable stonewash denim overalls with adjustable straps and roomy front pockets — built for a full day of play and easy to layer over any shirt.', '00000000-0000-0000-0000-000036e22902', '00000000-0000-0000-0000-00000d44de42', 29.99, NULL, '{"sizes":["2T","3T","4T","5T"]}'::jsonb, 4.3, 990, true, false),
('00000000-0000-0000-0000-00003ecde3e1', 'Toddler Graphic T-Shirt Pack', 'toddler-graphic-tshirt-pack', 'A pack of 3 soft cotton tees in playful graphic prints. Reinforced neckline seams hold up to daily wear and machine washing.', '00000000-0000-0000-0000-000036e22902', '00000000-0000-0000-0000-00000d44de42', 18.99, NULL, '{"sizes":["2T","3T","4T","5T","6T"]}'::jsonb, 4.4, 1345, true, true),
('00000000-0000-0000-0000-0000240a33e4', 'HRX Chicago Colorway Sneakers', 'hrx-chicago-colorway-sneakers', 'Perhaps the most iconic sneaker silhouette of all time, reissued in the legendary "Chicago" colorway. Full-grain leather upper, cushioned midsole, and a rubber outsole built to last.', '00000000-0000-0000-0000-00002902d1ec', '00000000-0000-0000-0000-00002d1b2c0d', 74.99, 149.99, '{"sizes":["6UK","7UK","8UK","9UK","10UK"]}'::jsonb, 4.1, 56890, true, true),
('00000000-0000-0000-0000-000035d15771', 'Air Zoom Running Shoes', 'air-zoom-running-shoes', 'Engineered mesh upper for breathability, with a responsive foam midsole tuned for daily training miles. Reflective details for low-light visibility.', '00000000-0000-0000-0000-000037143eba', '00000000-0000-0000-0000-00002d1b2c0d', 89.99, 119.99, '{"sizes":["7UK","8UK","9UK","10UK","11UK"]}'::jsonb, 4.5, 24678, true, true),
('00000000-0000-0000-0000-00000be30390', 'Men''s Slim Fit Chino Pants', 'mens-slim-fit-chino-pants', 'A tailored slim fit in stretch cotton twill that moves with you. Sits at the natural waist with a clean, no-fade finish wash after wash.', '00000000-0000-0000-0000-00002902d1ec', '00000000-0000-0000-0000-00002d1b2c0d', 34.99, NULL, '{"sizes":["30","32","34","36","38"],"colors":["Khaki","Navy","Black"]}'::jsonb, 4.2, 3140, true, false),
('00000000-0000-0000-0000-00001da9a71d', 'Men''s Bomber Jacket', 'mens-bomber-jacket', 'A classic bomber silhouette in a water-resistant shell with a soft quilted lining. Ribbed collar, cuffs, and hem for a snug, insulated fit.', '00000000-0000-0000-0000-000037143eba', '00000000-0000-0000-0000-00002d1b2c0d', 79.99, NULL, '{"sizes":["S","M","L","XL"]}'::jsonb, 4.3, 1890, true, false),
('00000000-0000-0000-0000-000028853cd9', 'Starry Sky Printed Shirt', 'starry-sky-printed-shirt', '100% cotton fabric with an all-over star print, cut for a relaxed, breathable fit. Button-down front and a single chest pocket.', '00000000-0000-0000-0000-00002902d1ec', '00000000-0000-0000-0000-00002d1b2c0d', 24.99, 31.99, '{"sizes":["S","M","L","XL"]}'::jsonb, 4.4, 152344, true, false),
('00000000-0000-0000-0000-00003e338262', 'Printed Wrap Kurta', 'printed-wrap-kurta', 'A relaxed-fit kurta in a soft printed viscose blend, with a wrap-style neckline and three-quarter sleeves. Pairs equally well with leggings or straight-leg pants.', '00000000-0000-0000-0000-00001b5c0823', '00000000-0000-0000-0000-00001c28a70b', 45.0, 75.0, '{"sizes":["XS","S","M","L","XL"]}'::jsonb, 4.2, 56890, true, true),
('00000000-0000-0000-0000-0000268c5311', 'Floral Tiered Maxi Dress', 'floral-tiered-maxi-dress', 'A flowing tiered maxi in a rust-and-black floral print, with a flattering elastic waist and adjustable straps. Fully lined for opacity.', '00000000-0000-0000-0000-00000fa3de02', '00000000-0000-0000-0000-00001c28a70b', 59.9, NULL, '{"sizes":["XS","S","M","L"]}'::jsonb, 4.1, 335566, true, false),
('00000000-0000-0000-0000-000034526e9d', 'Black Bodycon Mini Dress', 'black-bodycon-mini-dress', 'A figure-hugging bodycon in a smooth stretch knit, with a chain-detail shoulder strap and a versatile silhouette that works for both day and night.', '00000000-0000-0000-0000-00000fa3de02', '00000000-0000-0000-0000-00001c28a70b', 39.99, 59.99, '{"sizes":["XS","S","M","L"],"colors":["Black"]}'::jsonb, 4.3, 523456, true, true),
('00000000-0000-0000-0000-0000078094fb', 'Denim Shirt Dress', 'denim-shirt-dress', 'A button-through shirt dress in soft-washed denim, cinched with a tie belt at the waist. Roomy chest pockets and a relaxed, all-day silhouette.', '00000000-0000-0000-0000-00001b5c0823', '00000000-0000-0000-0000-00001c28a70b', 44.99, NULL, '{"sizes":["XS","S","M","L","XL"]}'::jsonb, 4.4, 27344, true, false),
('00000000-0000-0000-0000-0000153b3070', 'Pink Embroidered Tiered Maxi', 'pink-embroidered-tiered-maxi', 'A rose-pink maxi with delicate embroidered detailing along a tiered skirt. Lightweight and breathable, with a relaxed fit that flatters every body type.', '00000000-0000-0000-0000-00001b5c0823', '00000000-0000-0000-0000-00001c28a70b', 52.0, 68.0, '{"sizes":["XS","S","M","L"]}'::jsonb, 4.5, 45678, true, false);
